processors.dqlScript:
parse app, "JSON:record_json" 
| fieldsAdd task.id = hashSha1(concat(toString(toLong(now())), toString(RANDOM())))
| fieldsAdd task.name = "ArgoCD Deployment"
| fieldsFlatten record_json, fields:{status}
| fieldsAdd task.outcome = if(contains(lower(status[operationState][message]), "successfully"), 
  "success", 
  else: if(contains(lower(status[operationState][message]), "failure"),
  "failure",
  else: lower(status[operationState][message])))

